import { create, all } from 'mathjs';

const config = {};
const math = create(all, config);

export interface MathResult {
  result: number | string;
  expression: string;
  variables: Record<string, number>;
  error?: string;
}

export class MathCalculator {
  static evaluate(expression: string, variables: Record<string, number> = {}): MathResult {
    try {
      const result = math.evaluate(expression, variables);
      return {
        result,
        expression,
        variables,
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        expression,
        variables,
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static derivative(expression: string, variable: string): MathResult {
    try {
      const derivative = math.derivative(expression, variable);
      return {
        result: derivative.toString(),
        expression: `d/d${variable}(${expression})`,
        variables: {},
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        expression: `d/d${variable}(${expression})`,
        variables: {},
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static integrate(expression: string, variable: string, lower: number, upper: number): MathResult {
    try {
      const integral = math.integral(expression, variable);
      const result = integral.evaluate({ [variable]: upper }) - integral.evaluate({ [variable]: lower });
      return {
        result,
        expression: `∫_${lower}^{${upper}} ${expression} d${variable}`,
        variables: {},
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        expression: `∫_${lower}^{${upper}} ${expression} d${variable}`,
        variables: {},
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static solveEquation(expression: string, variable: string): MathResult[] {
    try {
      const solutions = math.simplify(expression).solve(variable);
      return solutions.map((solution, index) => ({
        result: solution.toString(),
        expression: `Solve ${expression} for ${variable}`,
        variables: {},
        error: undefined
      }));
    } catch (error) {
      return [{
        result: 'Error',
        expression: `Solve ${expression} for ${variable}`,
        variables: {},
        error: error instanceof Error ? error.message : 'Unknown error'
      }];
    }
  }

  static matrixOperations(matrix: number[][], operation: 'determinant' | 'inverse' | 'transpose'): MathResult {
    try {
      const mathMatrix = math.matrix(matrix);
      let result;

      switch (operation) {
        case 'determinant':
          result = math.det(mathMatrix);
          break;
        case 'inverse':
          result = math.inv(mathMatrix);
          break;
        case 'transpose':
          result = math.transpose(mathMatrix);
          break;
      }

      return {
        result: result.toString(),
        expression: `${operation}(${JSON.stringify(matrix)})`,
        variables: {},
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        expression: `${operation}(${JSON.stringify(matrix)})`,
        variables: {},
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static statistics(data: number[], operation: 'mean' | 'median' | 'variance' | 'std'): MathResult {
    try {
      let result;

      switch (operation) {
        case 'mean':
          result = math.mean(data);
          break;
        case 'median':
          result = math.median(data);
          break;
        case 'variance':
          result = math.variance(data);
          break;
        case 'std':
          result = math.std(data);
          break;
      }

      return {
        result,
        expression: `${operation}(${JSON.stringify(data)})`,
        variables: {},
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        expression: `${operation}(${JSON.stringify(data)})`,
        variables: {},
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static complexNumberOperations(a: string, b: string, operation: 'add' | 'subtract' | 'multiply' | 'divide'): MathResult {
    try {
      const complexA = math.complex(a);
      const complexB = math.complex(b);
      let result;

      switch (operation) {
        case 'add':
          result = math.add(complexA, complexB);
          break;
        case 'subtract':
          result = math.subtract(complexA, complexB);
          break;
        case 'multiply':
          result = math.multiply(complexA, complexB);
          break;
        case 'divide':
          result = math.divide(complexA, complexB);
          break;
      }

      return {
        result: result.toString(),
        expression: `${a} ${operation === 'add' ? '+' : operation === 'subtract' ? '-' : operation === 'multiply' ? '*' : '/'} ${b}`,
        variables: {},
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        expression: `${a} ${operation === 'add' ? '+' : operation === 'subtract' ? '-' : operation === 'multiply' ? '*' : '/'} ${b}`,
        variables: {},
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }
}

export interface FinancialResult {
  result: number | string;
  formula: string;
  parameters: Record<string, number>;
  error?: string;
}

export class FinancialCalculator {
  static compoundInterest(principal: number, rate: number, time: number, n: number = 1): FinancialResult {
    try {
      const amount = principal * Math.pow(1 + rate / n, n * time);
      const interest = amount - principal;

      return {
        result: amount,
        formula: `A = P(1 + r/n)^(nt)`,
        parameters: { principal, rate, time, n, amount, interest },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `A = P(1 + r/n)^(nt)`,
        parameters: { principal, rate, time, n },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static loanPayment(principal: number, rate: number, time: number, n: number = 12): FinancialResult {
    try {
      const monthlyRate = rate / n;
      const totalPayments = n * time;
      const payment = (principal * monthlyRate) / (1 - Math.pow(1 + monthlyRate, -totalPayments));
      const totalPayment = payment * totalPayments;
      const totalInterest = totalPayment - principal;

      return {
        result: payment,
        formula: `PMT = P * (r/n) / (1 - (1 + r/n)^(-nt))`,
        parameters: { 
          principal, 
          rate, 
          time, 
          n, 
          monthlyRate, 
          totalPayments, 
          payment, 
          totalPayment, 
          totalInterest 
        },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `PMT = P * (r/n) / (1 - (1 + r/n)^(-nt))`,
        parameters: { principal, rate, time, n },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static presentValue(futureValue: number, rate: number, time: number, n: number = 1): FinancialResult {
    try {
      const presentValue = futureValue / Math.pow(1 + rate / n, n * time);

      return {
        result: presentValue,
        formula: `PV = FV / (1 + r/n)^(nt)`,
        parameters: { futureValue, rate, time, n, presentValue },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `PV = FV / (1 + r/n)^(nt)`,
        parameters: { futureValue, rate, time, n },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static futureValue(presentValue: number, rate: number, time: number, n: number = 1): FinancialResult {
    try {
      const futureValue = presentValue * Math.pow(1 + rate / n, n * time);

      return {
        result: futureValue,
        formula: `FV = PV * (1 + r/n)^(nt)`,
        parameters: { presentValue, rate, time, n, futureValue },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `FV = PV * (1 + r/n)^(nt)`,
        parameters: { presentValue, rate, time, n },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static annuityPayment(presentValue: number, rate: number, time: number, n: number = 12): FinancialResult {
    try {
      const monthlyRate = rate / n;
      const totalPayments = n * time;
      const payment = (presentValue * monthlyRate) / (1 - Math.pow(1 + monthlyRate, -totalPayments));
      const totalPayment = payment * totalPayments;
      const totalInterest = totalPayment - presentValue;

      return {
        result: payment,
        formula: `PMT = PV * (r/n) / (1 - (1 + r/n)^(-nt))`,
        parameters: { 
          presentValue, 
          rate, 
          time, 
          n, 
          monthlyRate, 
          totalPayments, 
          payment, 
          totalPayment, 
          totalInterest 
        },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `PMT = PV * (r/n) / (1 - (1 + r/n)^(-nt))`,
        parameters: { presentValue, rate, time, n },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static bondPrice(faceValue: number, couponRate: number, marketRate: number, time: number, n: number = 2): FinancialResult {
    try {
      const periods = n * time;
      const periodRate = marketRate / n;
      const couponPayment = faceValue * couponRate / n;

      let price = 0;
      for (let i = 1; i <= periods; i++) {
        price += couponPayment / Math.pow(1 + periodRate, i);
      }
      price += faceValue / Math.pow(1 + periodRate, periods);

      return {
        result: price,
        formula: `P = Σ(CF_t / (1+r)^t) + (FV / (1+r)^n)`,
        parameters: { 
          faceValue, 
          couponRate, 
          marketRate, 
          time, 
          n, 
          periods, 
          periodRate, 
          couponPayment, 
          price 
        },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `P = Σ(CF_t / (1+r)^t) + (FV / (1+r)^n)`,
        parameters: { faceValue, couponRate, marketRate, time, n },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static depreciation(initialValue: number, salvageValue: number, life: number, method: 'straight-line' | 'double-declining'): FinancialResult {
    try {
      let depreciation = 0;
      let annualDepreciation = 0;

      switch (method) {
        case 'straight-line':
          annualDepreciation = (initialValue - salvageValue) / life;
          depreciation = annualDepreciation;
          break;
        case 'double-declining':
          const rate = 2 / life;
          depreciation = initialValue * rate;
          break;
      }

      return {
        result: depreciation,
        formula: method === 'straight-line' 
          ? `Annual Depreciation = (Initial - Salvage) / Life` 
          : `Depreciation = Initial * (2 / Life)`,
        parameters: { 
          initialValue, 
          salvageValue, 
          life, 
          method, 
          depreciation, 
          annualDepreciation 
        },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: method === 'straight-line' 
          ? `Annual Depreciation = (Initial - Salvage) / Life` 
          : `Depreciation = Initial * (2 / Life)`,
        parameters: { initialValue, salvageValue, life, method },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static netPresentValue(cashFlows: number[], discountRate: number): FinancialResult {
    try {
      let npv = 0;
      cashFlows.forEach((cashFlow, index) => {
        npv += cashFlow / Math.pow(1 + discountRate, index + 1);
      });

      return {
        result: npv,
        formula: `NPV = Σ(CF_t / (1+r)^t)`,
        parameters: { cashFlows, discountRate, npv },
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `NPV = Σ(CF_t / (1+r)^t)`,
        parameters: { cashFlows, discountRate },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static internalRateOfReturn(cashFlows: number[]): FinancialResult {
    try {
      // Simplified IRR calculation using Newton-Raphson method
      let rate = 0.1;
      const maxIterations = 100;
      const tolerance = 0.0001;

      for (let i = 0; i < maxIterations; i++) {
        let npv = 0;
        let dnpv = 0;

        cashFlows.forEach((cashFlow, index) => {
          const t = index + 1;
          npv += cashFlow / Math.pow(1 + rate, t);
          dnpv -= t * cashFlow / Math.pow(1 + rate, t + 1);
        });

        const newRate = rate - npv / dnpv;

        if (Math.abs(newRate - rate) < tolerance) {
          return {
            result: newRate,
            formula: `IRR (Newton-Raphson)`,
            parameters: { cashFlows, rate: newRate },
            error: undefined
          };
        }

        rate = newRate;
      }

      return {
        result: rate,
        formula: `IRR (Newton-Raphson)`,
        parameters: { cashFlows, rate },
        error: 'Did not converge'
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `IRR (Newton-Raphson)`,
        parameters: { cashFlows },
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }
}

export interface ScientificResult {
  result: number | string;
  formula: string;
  parameters: Record<string, number>;
  unit?: string;
  error?: string;
}

export class ScientificCalculator {
  static physicsForce(mass: number, acceleration: number): ScientificResult {
    try {
      const force = mass * acceleration;
      return {
        result: force,
        formula: `F = m * a`,
        parameters: { mass, acceleration, force },
        unit: 'N (Newtons)',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `F = m * a`,
        parameters: { mass, acceleration },
        unit: 'N (Newtons)',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static physicsVelocity(distance: number, time: number): ScientificResult {
    try {
      const velocity = distance / time;
      return {
        result: velocity,
        formula: `v = d / t`,
        parameters: { distance, time, velocity },
        unit: 'm/s',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `v = d / t`,
        parameters: { distance, time },
        unit: 'm/s',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static physicsAcceleration(initialVelocity: number, finalVelocity: number, time: number): ScientificResult {
    try {
      const acceleration = (finalVelocity - initialVelocity) / time;
      return {
        result: acceleration,
        formula: `a = (v_f - v_i) / t`,
        parameters: { initialVelocity, finalVelocity, time, acceleration },
        unit: 'm/s²',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `a = (v_f - v_i) / t`,
        parameters: { initialVelocity, finalVelocity, time },
        unit: 'm/s²',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static physicsKineticEnergy(mass: number, velocity: number): ScientificResult {
    try {
      const kineticEnergy = 0.5 * mass * Math.pow(velocity, 2);
      return {
        result: kineticEnergy,
        formula: `KE = 0.5 * m * v²`,
        parameters: { mass, velocity, kineticEnergy },
        unit: 'J (Joules)',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `KE = 0.5 * m * v²`,
        parameters: { mass, velocity },
        unit: 'J (Joules)',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static physicsPotentialEnergy(mass: number, height: number, gravity: number = 9.81): ScientificResult {
    try {
      const potentialEnergy = mass * gravity * height;
      return {
        result: potentialEnergy,
        formula: `PE = m * g * h`,
        parameters: { mass, height, gravity, potentialEnergy },
        unit: 'J (Joules)',
        error: undefined
      };
    } catch (error) {
