  }

  static physicsPressure(force: number, area: number): ScientificResult {
    try {
      const pressure = force / area;
      return {
        result: pressure,
        formula: `P = F / A`,
        parameters: { force, area, pressure },
        unit: 'Pa (Pascals)',
