        formula: `ρ = m / V`,
        parameters: { mass, volume },
        unit: 'kg/m³',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static temperatureConversion(value: number, from: 'C' | 'F' | 'K', to: 'C' | 'F' | 'K'): ScientificResult {
    try {
      let result = value;

      // Convert to Celsius first
      switch (from) {
        case 'F':
          result = (value - 32) * 5/9;
          break;
        case 'K':
          result = value - 273.15;
          break;
      }

      // Convert from Celsius to target
      switch (to) {
        case 'F':
          result = (result * 9/5) + 32;
          break;
        case 'K':
          result = result + 273.15;
          break;
      }

      return {
        result,
        formula: `${value}°${from} = ${result}°${to}`,
        parameters: { value, from, to, result },
        unit: `°${to}`,
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `${value}°${from} = ${value}°${to}`,
        parameters: { value, from, to },
        unit: `°${to}`,
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static speedOfSound(temperatureC: number, medium: 'air' | 'water' | 'steel'): ScientificResult {
    try {
      let speed = 0;

      switch (medium) {
        case 'air':
          speed = 331.3 * Math.sqrt(1 + temperatureC / 273.15);
          break;
        case 'water':
          speed = 1482; // Approximate at 20°C
          break;
        case 'steel':
          speed = 5960; // Approximate
          break;
      }

      return {
        result: speed,
        formula: medium === 'air' 
          ? `v = 331.3 * √(1 + T/273.15)` 
          : medium === 'water' 
          ? `v ≈ 1482 m/s` 
          : `v ≈ 5960 m/s`,
        parameters: { temperatureC, medium, speed },
        unit: 'm/s',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: medium === 'air' 
          ? `v = 331.3 * √(1 + T/273.15)` 
          : medium === 'water' 
          ? `v ≈ 1482 m/s` 
          : `v ≈ 5960 m/s`,
        parameters: { temperatureC, medium },
        unit: 'm/s',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static waveFrequency(wavelength: number, velocity: number): ScientificResult {
    try {
      const frequency = velocity / wavelength;
      return {
        result: frequency,
        formula: `f = v / λ`,
        parameters: { wavelength, velocity, frequency },
        unit: 'Hz',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `f = v / λ`,
        parameters: { wavelength, velocity },
        unit: 'Hz',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static opticsRefraction(angleOfIncidence: number, refractiveIndex1: number, refractiveIndex2: number): ScientificResult {
    try {
      const angleOfRefraction = Math.asin(
        (refractiveIndex1 * Math.sin(angleOfIncidence * Math.PI / 180)) / refractiveIndex2
      ) * 180 / Math.PI;

      return {
        result: angleOfRefraction,
        formula: `n₁ * sin(θ₁) = n₂ * sin(θ₂)`,
        parameters: { 
          angleOfIncidence, 
          refractiveIndex1, 
          refractiveIndex2, 
          angleOfRefraction 
        },
        unit: 'degrees',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `n₁ * sin(θ₁) = n₂ * sin(θ₂)`,
        parameters: { angleOfIncidence, refractiveIndex1, refractiveIndex2 },
        unit: 'degrees',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static electricityOhmLaw(voltage: number, current: number): ScientificResult {
    try {
      const resistance = voltage / current;
      return {
        result: resistance,
        formula: `R = V / I`,
        parameters: { voltage, current, resistance },
        unit: 'Ω (Ohms)',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `R = V / I`,
        parameters: { voltage, current },
        unit: 'Ω (Ohms)',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static electricityPower(voltage: number, current: number): ScientificResult {
    try {
      const power = voltage * current;
      return {
        result: power,
        formula: `P = V * I`,
        parameters: { voltage, current, power },
        unit: 'W (Watts)',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `P = V * I`,
        parameters: { voltage, current },
        unit: 'W (Watts)',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static chemistryMolarity(soluteMass: number, soluteMolarMass: number, volume: number): ScientificResult {
    try {
      const moles = soluteMass / soluteMolarMass;
      const molarity = moles / volume;
      return {
        result: molarity,
        formula: `M = (mass / molar mass) / volume`,
        parameters: { 
          soluteMass, 
          soluteMolarMass, 
          volume, 
          moles, 
          molarity 
        },
        unit: 'M (mol/L)',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `M = (mass / molar mass) / volume`,
        parameters: { soluteMass, soluteMolarMass, volume },
        unit: 'M (mol/L)',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static gasLaw(initialPressure: number, initialVolume: number, finalPressure: number, temperature: number = 298): ScientificResult {
    try {
      const finalVolume = (initialPressure * initialVolume) / finalPressure;
      return {
        result: finalVolume,
        formula: `P₁V₁ = P₂V₂`,
        parameters: { 
          initialPressure, 
          initialVolume, 
          finalPressure, 
          finalVolume, 
          temperature 
        },
        unit: 'L (Liters)',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `P₁V₁ = P₂V₂`,
        parameters: { initialPressure, initialVolume, finalPressure },
        unit: 'L (Liters)',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }

  static astronomyEscapeVelocity(mass: number, radius: number): ScientificResult {
    try {
      const G = 6.674 * Math.pow(10, -11);
      const escapeVelocity = Math.sqrt((2 * G * mass) / radius);
      return {
        result: escapeVelocity,
        formula: `v = √(2GM/r)`,
        parameters: { mass, radius, escapeVelocity },
        unit: 'm/s',
        error: undefined
      };
    } catch (error) {
      return {
        result: 'Error',
        formula: `v = √(2GM/r)`,
        parameters: { mass, radius },
        unit: 'm/s',
        error: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }
}

import { v4 as uuidv4 } from 'uuid';

export interface CalculationHistory {
  id: string;
  timestamp: Date;
  type: 'math' | 'financial' | 'scientific';
  expression: string;
  result: string;
  variables?: Record<string, number>;
  parameters?: Record<string, number>;
  unit?: string;
  error?: string;
}

export interface HistoryOptions {
  maxEntries?: number;
  storageKey?: string;
  autoSave?: boolean;
}

export class CalculationHistoryManager {
  private maxEntries: number;
  private storageKey: string;
  private autoSave: boolean;
  private history: CalculationHistory[] = [];

  constructor(options: HistoryOptions = {}) {
    this.maxEntries = options.maxEntries || 100;
    this.storageKey = options.storageKey || 'calculation_history';
    this.autoSave = options.autoSave !== false;

    this.load();
  }

  private load(): void {
    try {
      const stored = localStorage.getItem(this.storageKey);
      if (stored) {
        this.history = JSON.parse(stored);
      }
    } catch (error) {
      console.warn('Failed to load history from localStorage:', error);
      this.history = [];
    }
  }

  private save(): void {
    if (this.autoSave) {
      try {
        localStorage.setItem(this.storageKey, JSON.stringify(this.history));
      } catch (error) {
        console.warn('Failed to save history to localStorage:', error);
      }
    }
  }

  addEntry(entry: Omit<CalculationHistory, 'id' | 'timestamp'>): string {
    const newEntry: CalculationHistory = {
      ...entry,
      id: uuidv4(),
      timestamp: new Date()
    };

    this.history.unshift(newEntry);

    // Limit history size
    if (this.history.length > this.maxEntries) {
      this.history = this.history.slice(0, this.maxEntries);
    }

    this.save();
    return newEntry.id;
  }

  getEntries(limit?: number, offset: number = 0): CalculationHistory[] {
    const start = offset;
    const end = limit ? start + limit : this.history.length;
    return this.history.slice(start, end);
  }

  getEntryById(id: string): CalculationHistory | undefined {
    return this.history.find(entry => entry.id === id);
  }

  getEntriesByType(type: 'math' | 'financial' | 'scientific', limit?: number): CalculationHistory[] {
    const filtered = this.history.filter(entry => entry.type === type);
    return limit ? filtered.slice(0, limit) : filtered;
  }

  getEntriesByDateRange(startDate: Date, endDate: Date): CalculationHistory[] {
    return this.history.filter(entry => {
      return entry.timestamp >= startDate && entry.timestamp <= endDate;
    });
  }

  getMostFrequentExpressions(limit: number = 10): { expression: string; count: number }[] {
    const expressionMap = new Map<string, number>();

    this.history.forEach(entry => {
      const key = entry.expression;
      expressionMap.set(key, (expressionMap.get(key) || 0) + 1);
    });

    return Array.from(expressionMap.entries())
      .map(([expression, count]) => ({ expression, count }))
      .sort((a, b) => b.count - a.count)
      .slice(0, limit);
  }

  getAverageCalculationTime(): number {
    if (this.history.length === 0) return 0;

    // This would require timing data - for now return placeholder
    return 0;
  }

  getErrorRate(): number {
    if (this.history.length === 0) return 0;

    const errorCount = this.history.filter(entry => entry.error).length;
    return (errorCount / this.history.length) * 100;
  }

  clearHistory(): void {
    this.history = [];
    this.save();
  }

  removeEntry(id: string): boolean {
    const index = this.history.findIndex(entry => entry.id === id);
    if (index !== -1) {
      this.history.splice(index, 1);
      this.save();
      return true;
    }
    return false;
  }

  exportToCSV(): string {
    const rows = [
      'ID,Timestamp,Type,Expression,Result,Variables,Parameters,Unit,Error',
      ...this.history.map(entry => {
        const variables = entry.variables ? JSON.stringify(entry.variables) : '';
        const parameters = entry.parameters ? JSON.stringify(entry.parameters) : '';
        return `${entry.id},${entry.timestamp.toISOString()},${entry.type},${entry.expression},${entry.result},${variables},${parameters},${entry.unit || ''},${entry.error || ''}`;
      })
    ];

    return rows.join('\n');
  }

  exportToJSON(): string {
    return JSON.stringify(this.history, null, 2);
  }

  getStatistics(): {
    totalEntries: number;
    totalMath: number;
    totalFinancial: number;
    totalScientific: number;
    errorRate: number;
    mostFrequentExpressions: { expression: string; count: number }[];
  } {
    const totalMath = this.history.filter(e => e.type === 'math').length;
    const totalFinancial = this.history.filter(e => e.type === 'financial').length;
    const totalScientific = this.history.filter(e => e.type === 'scientific').length;
    const errorRate = this.getErrorRate();
    const mostFrequentExpressions = this.getMostFrequentExpressions(5);

    return {
      totalEntries: this.history.length,
      totalMath,
      totalFinancial,
      totalScientific,
      errorRate,
      mostFrequentExpressions
    };
  }

  // Search functionality
  search(query: string): CalculationHistory[] {
    const lowerQuery = query.toLowerCase();
    return this.history.filter(entry => {
      return entry.expression.toLowerCase().includes(lowerQuery) ||
             entry.result.toLowerCase().includes(lowerQuery) ||
             (entry.error && entry.error.toLowerCase().includes(lowerQuery));
    });
  }

  // Tag-based filtering (could be extended with actual tagging system)
  filterByTag(tag: string): CalculationHistory[] {
    // Simple implementation - could be enhanced with actual tags
    return this.history.filter(entry => {
      return entry.expression.toLowerCase().includes(tag.toLowerCase()) ||
             entry.result.toLowerCase().includes(tag.toLowerCase());
    });
  }

  // Export for backup/restore
  backup(): string {
    return JSON.stringify({
      version: '1.0',
      timestamp: new Date().toISOString(),
      history: this.history
    }, null, 2);
  }

  restore(backupData: string): boolean {
    try {
      const backup = JSON.parse(backupData);
      if (backup.version === '1.0' && Array.isArray(backup.history)) {
        this.history = backup.history;
        this.save();
        return true;
      }
    } catch (error) {
      console.warn('Failed to restore history:', error);
    }
    return false;
  }

  // Performance optimization: get recent entries without loading all
  getRecentEntries(count: number): CalculationHistory[] {
    return this.history.slice(0, count);
  }

  // Get entries for specific date
  getEntriesForDate(date: Date): CalculationHistory[] {
    const start = new Date(date);
    start.setHours(0, 0, 0, 0);
    const end = new Date(start);
    end.setHours(23, 59, 59, 999);

    return this.getEntriesByDateRange(start, end);
  }

  // Get entries for current week
  getEntriesForCurrentWeek(): CalculationHistory[] {
    const now = new Date();
    const dayOfWeek = now.getDay();
    const startOfWeek = new Date(now);
    startOfWeek.setDate(now.getDate() - dayOfWeek);
    startOfWeek.setHours(0, 0, 0, 0);

    const endOfWeek = new Date(startOfWeek);
    endOfWeek.setDate(endOfWeek.getDate() + 6);
    endOfWeek.setHours(23, 59, 59, 999);

    return this.getEntriesByDateRange(startOfWeek, endOfWeek);
  }

  // Get entries for current month
  getEntriesForCurrentMonth(): CalculationHistory[] {
    const now = new Date();
    const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
    const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

    return this.getEntriesByDateRange(startOfMonth, endOfMonth);
  }

  // Get entries for current year
  getEntriesForCurrentYear(): CalculationHistory[] {
    const now = new Date();
    const startOfYear = new Date(now.getFullYear(), 0, 1);
    const endOfYear = new Date(now.getFullYear(), 11, 31);

    return this.getEntriesByDateRange(startOfYear, endOfYear);
  }

  // Get calculation trends
  getCalculationTrends(): {
    daily: number[];
    weekly: number[];
    monthly: number[];
  } {
    // This would require more sophisticated time-series analysis
    // For now, return placeholder data
    return {
      daily: Array(7).fill(0),
      weekly: Array(4).fill(0),
      monthly: Array(12).fill(0)
    };
  }
}

import React from 'react';
