    mostUsedFunctions
  } = usePerformanceMetrics(calculations);

  return (
    <Card className="w-full max-w-2xl">
      <CardHeader>
        <CardTitle>Performance Metrics</CardTitle>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="grid grid-cols-2 gap-4 sm:grid-cols-4">
          <div className="bg-blue-50 p-4 rounded-lg">
            <p className="text-sm text-gray-600">Calculations</p>
            <p className="text-2xl font-bold text-blue-600">{calculationCount}</p>
          </div>
          <div className="bg-green-50 p-4 rounded-lg">
            <p className="text-sm text-gray-600">Avg Time</p>
            <p className="text-2xl font-bold text-green-600">{averageCalculationTime?.toFixed(3) || 0}ms</p>
          </div>
          <div className="bg-purple-50 p-4 rounded-lg">
            <p className="text-sm text-gray-600">Memory</p>
            <p className="text-2xl font-bold text-purple-600">{memoryUsage?.toFixed(2) || 0}MB</p>
          </div>
          <div className="bg-red-50 p-4 rounded-lg">
            <p className="text-sm text-gray-600">Error Rate</p>
            <p className="text-2xl font-bold text-red-600">{errorRate?.toFixed(1) || 0}%</p>
          </div>
        </div>

        <div>
          <h3 className="text-sm font-medium text-gray-900 mb-2">Top Functions</h3>
          <div className="space-y-2">
            {mostUsedFunctions?.slice(0, 5).map((func: any) => (
              <Badge key={func.name} className="text-sm">
                {func.name} ({func.count})
              </Badge>
            ))}
          </div>
        </div>

        <div>
          <h3 className="text-sm font-medium text-gray-900 mb-2">Recent Performance</h3>
          <div className="bg-gray-50 p-3 rounded-lg">
            <p className="text-xs text-gray-500">
              Last calculation took {calculations[calculations.length - 1]?.duration?.toFixed(3) || 0}ms
            </p>
          </div>
        </div>
      </CardContent>
    </Card>
  );
};

import { NextRequest, NextResponse } from 'next/server';
import { json2csv } from 'json-2-csv';
import { PDFDocument } from 'pdfkit';
import { Blob } from 'buffer';

export async function POST(request: NextRequest) {
  const { filename, data, format } = await request.json();

  try {
    let response: Response;
    let contentType: string;

    switch (format) {
      case 'csv':
        const csv = await json2csv(data, {
          emptyFieldValue: '',
          excelBOM: true,
          delimiter: {
            field: ',',
            wrap: '"',
            eof: '\n'
          }
        });

        response = new Response(csv, {
          headers: {
            'Content-Type': 'text/csv',
            'Content-Disposition': `attachment; filename="${filename}"`
          }
        });
        contentType = 'text/csv';
        break;

      case 'json':
        response = new Response(JSON.stringify(data, null, 2), {
          headers: {
            'Content-Type': 'application/json',
            'Content-Disposition': `attachment; filename="${filename}"`
          }
        });
        contentType = 'application/json';
        break;

      case 'pdf':
        const pdfDoc = new PDFDocument();
        const chunks: Uint8Array[] = [];

        pdfDoc.on('data', (chunk) => chunks.push(chunk));

        pdfDoc.fontSize(12).text('Calculation History', {
          align: 'center',
          underline: true
        });

        pdfDoc.moveDown();

        data.forEach((item: any, index: number) => {
          pdfDoc.fontSize(10).text(`${index + 1}. ${item.expression} = ${item.result}`, {
            marginBottom: 5
          });
        });

        pdfDoc.end();

        const pdfBuffer = await new Promise<Buffer>(resolve => {
          pdfDoc.on('end', () => {
            const pdfData = Buffer.concat(chunks);
            resolve(pdfData);
          });
        });

        response = new Response(pdfBuffer, {
          headers: {
            'Content-Type': 'application/pdf',
            'Content-Disposition': `attachment; filename="${filename}"`
          }
        });
        contentType = 'application/pdf';
        break;

      default:
        return NextResponse.json(
          { error: 'Invalid format' },
          { status: 400 }
        );
    }

    return NextResponse.json(
      { 
        success: true, 
        contentType,
        filename 
      },
      { status: 200 }
    );

  } catch (error) {
    console.error('Export error:', error);
    return NextResponse.json(
      { error: 'Export failed' },
      { status: 500 }
    );
  }
}

export async function GET() {
  return NextResponse.json(
    { 
      error: 'Export requires POST request with data', 
      formats: ['csv', 'json', 'pdf'] 
    },
    { status: 405 }
  );
}
